package com.amaya.intelligence.impl.ide.antigravity.services.event

import com.amaya.intelligence.data.remote.api.MessageRole
import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.impl.ide.antigravity.client.*
import com.amaya.intelligence.impl.ide.antigravity.tools.AntigravityToolMapper
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager

/**
 * Handles tool call events (start, result) from Antigravity.
 */
class ToolCallEventHandler(
    private val stateManager: StreamingStateManager,
    private val onUiStateUpdate: ((ChatUiState) -> ChatUiState) -> Unit
) {
    fun handleToolCallStart(event: RemoteEvent.ToolCallStart, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        stateManager.setPhase(StreamingStateManager.StreamPhase.TOOL)

        val normalizedName = AntigravityToolMapper.mapToolName(event.name)
        val normalizedArgs = AntigravityToolMapper.mapToolArgs(event.name, event.arguments)
        val uiMeta = AntigravityToolMapper.getUiMetadata(event.name, event.arguments)

        val status = when (event.status.uppercase()) {
            "PENDING", "WAITING", "STANDBY" -> ToolStatus.PENDING
            "RUNNING" -> ToolStatus.RUNNING
            "SUCCESS" -> ToolStatus.SUCCESS
            "ERROR"   -> ToolStatus.ERROR
            else      -> ToolStatus.RUNNING
        }

        val toolExec = ToolExecution(
            toolCallId = event.toolCallId,
            name = normalizedName,
            arguments = normalizedArgs,
            status = status,
            metadata = mapOf(
                "source" to "remote",
                "animateOnMount" to "true"
            ),
            uiMetadata = uiMeta
        )
        val timelineToolExec = toolExec.copy(
            name = normalizedName,
            arguments = normalizedArgs,
            status = status,
            metadata = toolExec.metadata + mapOf("source" to "remote"),
            uiMetadata = uiMeta
        )

        onUiStateUpdate { state ->
            val finalizedMsgs = finalizeRunningThinkingOnLastAssistant(state.messages)
            val msgs = ensureAssistantMessage(finalizedMsgs, force = false)
            val timelineUpdated = upsertToolTimelineItem(
                msgs,
                event.toolCallId,
                timelineToolExec
            )
            val updatedMsgs = if (timelineUpdated != null) {
                timelineUpdated
            } else {
                val toolUpdated = updateToolInMessages(msgs, event.toolCallId) { tool ->
                    tool.copy(
                        name = normalizedName,
                        arguments = normalizedArgs,
                        status = resolveStickyToolStatus(tool.status, status),
                        metadata = tool.metadata + mapOf("source" to "remote"),
                        uiMetadata = uiMeta
                    )
                }
                if (toolUpdated != null) {
                    toolUpdated
                } else {
                    updateLastAssistantMessage(msgs) { msg ->
                        msg.copy(
                            toolExecutions = msg.toolExecutions + toolExec,
                            isThinking = false
                        )
                    }
                }
            }
            state.copy(messages = updatedMsgs)
        }
        return true
    }

    fun handleToolActivity(event: RemoteEvent.ToolActivity, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        if (!event.type.equals("terminal", ignoreCase = true)) return false
        val chunk = event.terminalData
        if (chunk.isBlank()) return true

        onUiStateUpdate { state ->
            val updated = appendTerminalChunkToLatestRunningShellTool(state.messages, chunk)
            state.copy(messages = updated)
        }
        return true
    }

    fun handleToolCallResult(event: RemoteEvent.ToolCallResult, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        stateManager.setPhase(StreamingStateManager.StreamPhase.TOOL)
        val extractedResult = AntigravityToolMapper.extractToolResult(event.result)

        onUiStateUpdate { state ->
            val updatedMsgs = upsertToolTimelineItem(
                state.messages,
                event.toolCallId,
                null,
                updateOnly = { tool ->
                    tool.copy(
                        result = if (tool.name.equals("run_shell", ignoreCase = true) && !tool.result.isNullOrBlank() && extractedResult.trim().equals("done", ignoreCase = true)) {
                            tool.result
                        } else {
                            extractedResult
                        },
                        status = resolveStickyToolStatus(tool.status, if (event.isError) ToolStatus.ERROR else ToolStatus.SUCCESS)
                    )
                }
            ) ?: updateToolInMessages(state.messages, event.toolCallId) { tool ->
                val isPlaceholder = extractedResult.trim().equals("done", ignoreCase = true) ||
                    extractedResult.trim().equals("success", ignoreCase = true)
                val hasStreamedOutput = !tool.result.isNullOrBlank()

                tool.copy(
                    result = if (tool.name.equals("run_shell", ignoreCase = true) && hasStreamedOutput && isPlaceholder) {
                        tool.result
                    } else {
                        extractedResult
                    },
                    status = resolveStickyToolStatus(tool.status, if (event.isError) ToolStatus.ERROR else ToolStatus.SUCCESS)
                )
            } ?: state.messages
            state.copy(messages = updatedMsgs)
        }
        return true
    }

    private fun isForActiveConversation(eventConversationId: String?, currentConversationId: String?): Boolean {
        if (eventConversationId.isNullOrBlank()) return true
        if (currentConversationId.isNullOrBlank()) return true
        return eventConversationId == currentConversationId
    }

    private fun finalizeRunningThinkingOnLastAssistant(messages: List<UiMessage>): List<UiMessage> {
        val idx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (idx == -1) return messages

        val msg = messages[idx]
        if (!hasSyntheticThinkingTool(msg)) return messages

        val updatedTools = msg.toolExecutions.map { tool ->
            if ((tool.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                    tool.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)) &&
                tool.status == ToolStatus.RUNNING
            ) {
                tool.copy(status = ToolStatus.SUCCESS)
            } else {
                tool
            }
        }
        return messages.toMutableList().apply { this[idx] = msg.copy(toolExecutions = updatedTools) }
    }

    private fun hasSyntheticThinkingTool(message: UiMessage): Boolean {
        return message.toolExecutions.any {
            it.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                it.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)
        }
    }

    private fun ensureAssistantMessage(messages: List<UiMessage>, force: Boolean): List<UiMessage> {
        val lastMsg = messages.lastOrNull()
        if (lastMsg?.role == MessageRole.ASSISTANT) return messages

        val hasAssistantPlaceholder = lastMsg?.role == MessageRole.ASSISTANT &&
            lastMsg.content.isBlank() &&
            lastMsg.thinking.isNullOrBlank() &&
            lastMsg.toolExecutions.isEmpty()

        if (!force && hasAssistantPlaceholder) return messages

        return messages + UiMessage(role = MessageRole.ASSISTANT, content = "")
    }

    private fun updateLastAssistantMessage(
        messages: List<UiMessage>,
        update: (UiMessage) -> UiMessage
    ): List<UiMessage> {
        val idx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (idx == -1) return messages

        val updated = messages.toMutableList()
        updated[idx] = update(updated[idx])
        return updated
    }

    private fun updateToolInMessages(
        messages: List<UiMessage>,
        toolCallId: String,
        update: (ToolExecution) -> ToolExecution
    ): List<UiMessage>? {
        for (i in messages.indices.reversed()) {
            val msg = messages[i]
            val toolIdx = msg.toolExecutions.indexOfFirst { it.toolCallId == toolCallId }
            if (toolIdx != -1) {
                val updatedTools = msg.toolExecutions.toMutableList()
                updatedTools[toolIdx] = update(updatedTools[toolIdx])
                return messages.toMutableList().apply { this[i] = msg.copy(toolExecutions = updatedTools) }
            }
        }
        return null
    }

    private fun upsertToolTimelineItem(
        messages: List<UiMessage>,
        toolCallId: String,
        toolExecution: ToolExecution?,
        updateOnly: ((ToolExecution) -> ToolExecution)? = null
    ): List<UiMessage>? {
        for (i in messages.indices.reversed()) {
            val msg = messages[i]
            if (msg.role != MessageRole.ASSISTANT || msg.timelineItems.isEmpty()) continue

            val existingIdx = msg.timelineItems.indexOfFirst { it.id == toolCallId }
            if (existingIdx == -1) continue

            val updatedItems = msg.timelineItems.toMutableList()
            val existing = updatedItems[existingIdx]
            val updatedExecution = when {
                updateOnly != null && existing.toolExecution != null -> updateOnly(existing.toolExecution)
                toolExecution != null -> toolExecution
                else -> existing.toolExecution
            }
            val executionCandidate = updatedExecution ?: existing.toolExecution
            val stickyExecution = executionCandidate?.copy(
                status = resolveStickyToolStatus(existing.toolExecution?.status, executionCandidate.status),
                metadata = existing.toolExecution?.metadata.orEmpty() + executionCandidate.metadata,
                uiMetadata = executionCandidate.uiMetadata ?: existing.toolExecution?.uiMetadata
            )
            updatedItems[existingIdx] = existing.copy(
                toolExecution = stickyExecution,
                metadata = stickyExecution?.metadata ?: existing.metadata,
                text = stickyExecution?.result ?: existing.text
            )

            return messages.toMutableList().apply {
                this[i] = msg.copy(
                    timelineItems = updatedItems,
                    toolExecutions = updatedItems.mapNotNull { it.toolExecution }
                )
            }
        }

        if (toolExecution == null) return null

        val lastAssistantIdx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (lastAssistantIdx < 0) return null

        val msg = messages[lastAssistantIdx]
        val updatedItems = msg.timelineItems.toMutableList()
        updatedItems.add(
            MessageTimelineItem(
                id = toolCallId,
                type = if (toolExecution.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                    toolExecution.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)
                ) MessageTimelineItemType.THINKING else MessageTimelineItemType.TOOL_CALL,
                toolExecution = toolExecution,
                metadata = toolExecution.metadata,
                text = toolExecution.result
            )
        )
        return messages.toMutableList().apply {
            this[lastAssistantIdx] = msg.copy(
                timelineItems = updatedItems,
                toolExecutions = updatedItems.mapNotNull { it.toolExecution }
            )
        }
    }

    private fun resolveStickyToolStatus(local: ToolStatus?, incoming: ToolStatus): ToolStatus {
        val localRank = toolStatusRank(local)
        val incomingRank = toolStatusRank(incoming)
        return if (localRank >= incomingRank) local ?: incoming else incoming
    }

    private fun toolStatusRank(status: ToolStatus?): Int {
        return when (status) {
            ToolStatus.PENDING -> 0
            ToolStatus.RUNNING -> 1
            ToolStatus.SUCCESS -> 2
            ToolStatus.ERROR -> 3
            null -> -1
        }
    }

    private fun appendTerminalChunkToLatestRunningShellTool(messages: List<UiMessage>, chunk: String): List<UiMessage> {
        val sanitizedChunk = chunk
        // Walk backwards so we update the latest relevant tool execution.
        for (i in messages.indices.reversed()) {
            val msg = messages[i]
            if (msg.role != MessageRole.ASSISTANT) continue

            val toolIdx = msg.toolExecutions.indexOfLast {
                it.name.equals("run_shell", ignoreCase = true) &&
                    (it.status == ToolStatus.RUNNING || it.status == ToolStatus.PENDING)
            }
            if (toolIdx == -1) continue

            val tools = msg.toolExecutions.toMutableList()
            val existing = tools[toolIdx].result ?: ""
            val merged = if (existing.isBlank()) sanitizedChunk else (existing + sanitizedChunk)
            tools[toolIdx] = tools[toolIdx].copy(result = merged)
            val updatedMsg = msg.copy(toolExecutions = tools)
            return messages.toMutableList().apply { this[i] = updatedMsg }
        }
        return messages
    }
}

