if (isoRe.test(formattedResetTime)) {
    const date = new Date(formattedResetTime);
    formattedResetTime = `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} jam ${pad(date.getHours())}:${pad(date.getMinutes())}`;
}
console.log('Test 4 (handleSendMessage logic):', `Model "${selectedModel.label}" quota is exhausted. Quota will reset at ${formattedResetTime}.`);
